INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000063', '플리마켓 디피 꿀팁 공유해요', '디피할 때 높낮이 차이를 주면 시선이 잘 가요. 우드 박스로 단 만들고, 린넨 천 깔고, LED 스트링라이트 달면 분위기 확 달라져요!', '자유게시판', 'seller', '윤도윤', false, 12, NOW() - interval '20 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000004', '거스름돈 얼마나 준비하세요?', '다음 주 첫 플리마켓인데 거스름돈 준비가 고민이에요. 천원짜리 30장, 오천원짜리 10장이면 될까요?', '자유게시판', 'seller', '황서윤', false, 17, NOW() - interval '22 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000094', '카드 결제 단말기 추천', '토스, 페이코, 키오스크 뭐가 좋을까요? 수수료도 비교해보고 싶어요.', '자유게시판', 'foodtruck', '전채원', false, 18, NOW() - interval '12 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000033', '혼자 플리마켓 참가하시는 분?', '화장실 갈 때가 제일 곤란해요. 옆 부스 셀러분께 부탁하거나 잠깐 비우는데... 팁 있으신가요?', '자유게시판', 'seller', '서서윤', false, 47, NOW() - interval '8 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000021', '여름 야외 마켓 생존 키트', '선크림, 미니 선풍기, 얼음물 텀블러, 양산, 쿨타올, 모기 퇴치 스프레이. 이것만 해도 생존 가능!', '자유게시판', 'seller', '이지우', false, 30, NOW() - interval '29 days');
