INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000065', '혼자 플리마켓 참가하시는 분? (41)', '화장실 갈 때가 제일 곤란해요. 옆 부스 셀러분께 부탁하거나 잠깐 비우는데... 팁 있으신가요?', '자유게시판', 'seller', '이예은', false, 8, NOW() - interval '19 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000075', '여름 야외 마켓 생존 키트 (90)', '선크림, 미니 선풍기, 얼음물 텀블러, 양산, 쿨타올, 모기 퇴치 스프레이. 이것만 해도 생존 가능!', '자유게시판', 'seller', '장서진', false, 1, NOW() - interval '24 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000034', '포장재 어디서 구매하시나요? (12)', '크래프트 봉투, 스티커, 리본 등 포장재 대량 구매처 추천 부탁드려요.', '자유게시판', 'seller', '이현우', false, 0, NOW() - interval '4 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000093', '같이 참가할 파트너 구합니다 (62)', '서울/경기 플리마켓 같이 참가할 분! 부스비 반반, 판매도 번갈아가면서. 품목: 악세사리', '자유게시판', 'foodtruck', '최지윤', false, 27, NOW() - interval '21 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000057', 'SNS 마케팅 효과 있나요? (67)', '인스타로 마켓 참가 소식 올리는데 실제 매출과 연결되는지 모르겠어요.', '자유게시판', 'seller', '서예은', false, 24, NOW() - interval '22 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000088', '셀러 명함 만드셨나요? (51)', '인스타 QR코드 넣으면 좋다던데 어디서 인쇄하시나요?', '자유게시판', 'foodtruck', '서수아', false, 15, NOW() - interval '12 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, likes, created_at) VALUES ('f1000000-0000-0000-0000-000000000012', '푸드트럭 창업 비용 현실 (99)', '트럭 2500만, 개조비 800만, 장비 500만. 월 순수익 150~200만 정도예요.', '자유게시판', 'seller', '이민준', false, 23, NOW() - interval '20 days');
